+    confidence += if velocity_samples >= 15 {
+        0.30
+    } else if velocity_samples >= 5 {
+        0.20
+    } else if velocity_samples >= 1 {
+        0.10
+    } else {
+        -0.05
+    };
+
+    if issue.labels.is_empty() {
+        confidence -= 0.05;
+    }
