+        let mut bc = vec![0.0_f64; n];
+        for source in 0..n {
+            self.single_source_betweenness(source, &mut bc);
+        }
+
+        self.map_from_f64_scores(&bc)
+    }
+
+    fn compute_betweenness_sampled(&self, sample_size: usize) -> HashMap<String, f64> {
+        let n = self.node_to_id.len();
