+                    .unwrap_or_default();
+                let betweenness = self
+                    .metrics
+                    .betweenness
+                    .get(&issue.id)
+                    .copied()
+                    .unwrap_or_default();
+                let blocks_count = self
+                    .metrics
+                    .blocks_count
+                    .get(&issue.id)
+                    .copied()
+                    .unwrap_or_default();
+
+                // PageRank + betweenness favors central blockers and bridges.
+                let score = pagerank + (0.1 * betweenness);
+
+                InsightItem {
+                    id: issue.id.clone(),
+                    title: issue.title.clone(),
+                    score,
+                    blocks_count,
+                }
