+                .blocks_count
+                .cmp(&left.blocks_count)
+                .then_with(|| right.score.total_cmp(&left.score))
+                .then_with(|| left.id.cmp(&right.id))
+        });
+        bottlenecks.truncate(15);
+
+        let mut critical_path = self
+            .metrics
+            .critical_depth
+            .iter()
+            .filter_map(|(id, depth)| {
