+fn base_suggestion(
+    generated_at: &str,
+    suggestion_type: SuggestionType,
+    target_bead: String,
+    summary: String,
+    reason: String,
+    confidence: f64,
+) -> Suggestion {
+    Suggestion {
+        suggestion_type,
+        target_bead,
+        related_bead: None,
+        summary,
+        reason,
+        confidence,
+        action_command: None,
+        generated_at: generated_at.to_string(),
+        metadata: BTreeMap::new(),
+    }
+}
