+}
+
+impl Sprint {
+    #[must_use]
+    pub fn is_active_at(&self, now: DateTime<Utc>) -> bool {
+        let Some(start_date) = self.start_date else {
+            return false;
+        };
+        let Some(end_date) = self.end_date else {
